from sys import stdin

MOD = 10**9 + 7

def count_numbers(m, k):
    # Initialization of the dynamic programming table
    dp = [[[0] * (m + 1) for _ in range(10)] for _ in range(k + 1)]

    # Base cases
    for digit in range(1, 10):
        dp[1][digit][1] = 1

    # Update the dynamic programming table
    for length in range(2, k + 1):
        for last_digit in range(10):
            for count in range(1, m + 1):
                for prev_digit in range(10):
                    if last_digit == prev_digit:
                        if count > 1:
                            dp[length][last_digit][count] += dp[length - 1][prev_digit][count - 1]
                    else:
                        dp[length][last_digit][count] += dp[length - 1][prev_digit][count]
                    dp[length][last_digit][count] %= MOD

    # Calculate the answer
    ans = 0
    for last_digit in range(10):
        for count in range(1, m + 1):
            ans += dp[k][last_digit][count]
            ans %= MOD

    return ans

